const workbook = new ExcelJS.Workbook();
workbook.creator = "Codex";
workbook.lastModifiedBy = "Codex";
workbook.created = new Date();
workbook.modified = new Date();

const ws = workbook.addWorksheet("Matriz Registro Web", {
  views: [{ state: "frozen", ySplit: 1, xSplit: 4 }],
  properties: { defaultRowHeight: 72 },
});

ws.columns = columns.map(([header, key, width]) => ({
  header,
  key,
  width,
  style: { alignment: { vertical: "top", wrapText: true } },
}));

ws.addRows(rows);
ws.autoFilter = {
  from: { row: 1, column: 1 },
  to: { row: 1, column: columns.length },
};

const fills = {
  header: "FF1F4E78",
  green: "FFB7E1CD",
  amber: "FFFFE599",
  red: "FFF4CCCC",
  gray: "FFE7E6E6",
  white: "FFFFFFFF",
};

function statusFill(value) {
  const text = String(value || "").toUpperCase();
  if (text.includes("ROJO")) return fills.red;
  if (text.includes("AMBAR") || text.includes("ÁMBAR")) return fills.amber;
  if (text.includes("VERDE")) return fills.green;
  return null;
}

ws.getRow(1).height = 34;
ws.getRow(1).font = { bold: true, color: { argb: fills.white } };
ws.getRow(1).fill = { type: "pattern", pattern: "solid", fgColor: { argb: fills.header } };
ws.getRow(1).alignment = { vertical: "middle", horizontal: "center", wrapText: true };

for (let rowNumber = 2; rowNumber <= ws.rowCount; rowNumber += 1) {
  const rowRef = ws.getRow(rowNumber);
  rowRef.height = 84;
  for (let colNumber = 1; colNumber <= columns.length; colNumber += 1) {
    const cell = rowRef.getCell(colNumber);
    cell.alignment = { vertical: "top", wrapText: true };
    cell.border = {
      top: { style: "thin", color: { argb: "FFD9D9D9" } },
      left: { style: "thin", color: { argb: "FFD9D9D9" } },
      bottom: { style: "thin", color: { argb: "FFD9D9D9" } },
      right: { style: "thin", color: { argb: "FFD9D9D9" } },
    };
  }
  const statusCell = rowRef.getCell("estado");
  const fill = statusFill(statusCell.value);
  if (fill) {
    statusCell.fill = { type: "pattern", pattern: "solid", fgColor: { argb: fill } };
    statusCell.font = { bold: true };
  }
}

ws.getColumn("id").font = { bold: true };
ws.getColumn("prioridad").alignment = { vertical: "top", horizontal: "center", wrapText: true };

try {
  await workbook.xlsx.writeFile(outFile);
  console.log(outFile);
} catch (error) {
  if (error?.code !== "EBUSY") throw error;
  await workbook.xlsx.writeFile(fallbackOutFile);
  console.log(fallbackOutFile);
}
